var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"12:10 ARC-KP1\\n어느 사무실\\n<color=#ff3636>사건 발생</color> 12시간 경과","JPN":"12:10 ARC-KP1\\nとある事務所\\n<color=#ff3636>事件発生から</color>12時間経過","ENG":"12:10 ARC-KP1\\nUnknown Office\\n12 hours after <color=#ff3636>Incident</color>","TWN":"12:10 ARC-KP1\\n某個辦公室\\n<color=#ff3636>事件發生</color>後經過12個小時"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"밑천 마련하러 가던 길에 만나다니 이런 우연이 다 있구나.","JPN":"資金調達に向かう途中で会うなんて奇遇ね。","ENG":"What a coincidence seeing you here while I’m on my way to collect my funds.","TWN":"我原本正要去弄點錢，結果竟然遇到你，有這麼巧的事！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"자, 들어와라.","JPN":"さあ、入りなさい。","ENG":"Well, come in.","TWN":"快進來吧！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"와아……. 굉장해요.","JPN":"わあ……すごいですね。","ENG":"Wow... This place is wonderful.","TWN":"哇……好厲害喔。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"후훗, 그래, 대단하지 않느냐.","JPN":"ふふっ、そうでしょう、すごいでしょう。","ENG":"Ha ha. It sure is.","TWN":"呵呵，是不是？很厲害吧！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"예로부터 세상을 바꾼 인재들은 차고와 벽장에서 사업을 시작했지.","JPN":"昔から世界を変えた人たちは、ガレージや屋根裏部屋でビジネスを始めたのよ。","ENG":"We’ve all heard the tales of geniuses starting their businesses in their garages.","TWN":"自古以來，那些改變世界的人，都是從一個小倉庫或壁櫥裡起步的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"여기는 썩어빠진 알파트릭스 그룹을 내 발 아래 굴복시킬 야심찬 첫 걸음!","JPN":"ここは腐ったアルファトリックスグループを屈服させるための第一歩！","ENG":"This is where I start my journey to make the rotting Alphatrix Group mine!","TWN":"而這裡，就是我改變腐敗的阿爾法崔克斯集團的第一步！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"<color=#ffd34c>베타트릭스</color> 1호점이니라!!","JPN":"<color=#ffd34c>ベータトリックス</color>1号店よ！！","ENG":"I call it <color=#ffd34c>Betatrix</color> No. 1!!","TWN":"<color=#ffd34c>貝塔崔克斯</color>1號店！！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L13_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그렇군요!","JPN":"そうなんですね！","ENG":"Wonderful!","TWN":"原來如此！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님이 세운 알파트릭스가 무너지면 슬프겠지만…….","JPN":"お祖父様が設立したアルファトリックスが崩れてしまったら、さみしくなりますが……","ENG":"Grandfather might be sad to hear his company shut down, but...","TWN":"雖然爺爺一手打造起來的阿爾法崔克斯，就這樣瓦解的話會有點難過……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"무척 멋진 꿈이라고 생각해요!","JPN":"とってもステキな夢だと思います！","ENG":"I think your dream is splendid!","TWN":"但我覺得這是個很棒的夢想！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래. 지아는 아버지 말대로 정말 총명하구나. 과연 베타트릭스 영입 대상 1호다워.","JPN":"そうよね。ユイちゃんは父さんの言うとおり、本当に聡明だわ。\\nベータトリックスのスカウト対象第1号に相応しいわね。","ENG":"Yes. Father always said you were the brilliant one, Jia. You’re actually the first employee I want to recruit.","TWN":"沒錯！小佳，你果真像爸所說的一樣，很聰明呢！不愧是貝塔崔克斯第一個要拉攏的對象！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……영입 대상?","JPN":"……スカウト対象？","ENG":"...R-recruit?","TWN":"……要拉攏的對象？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아차……! 속마음을 들켜버렸구나!","JPN":"しまった……！　本音が漏れてしまったわ！","ENG":"Oops...! I guess I blurted out what was on my mind.","TWN":"哎呀……！不小心說出我的心底話！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"흠흠. 방금 얘기는 잊으렴.","JPN":"こほん、今の話は忘れなさい。","ENG":"Ahem. Please forget what I just said.","TWN":"沒事，剛的話就當作沒聽到。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그런데, 지아야. 너는 왜 그런 후미진 골목에서 울고 있었느냐?","JPN":"ところでユイちゃん。君はどうしてあんな路地裏で泣いていたのかしら。","ENG":"But Jia, why were you crying in that run down alleyway?","TWN":"不過小佳，你剛為什麼一個人在暗巷裡哭呢？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 전 울지 않았는걸요?","JPN":"えっ？　私、泣いてませんよ？","ENG":"Hmm? I wasn’t crying.","TWN":"嗯？我沒有哭啊？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"울었다는 건 네 마음 얘기란다. 네 마음이 우는 소리가 들리더구나.","JPN":"泣いていたのは君の心よ。心の泣き声が聞こえたの。","ENG":"It's a figurative expression. You looked devastated, mentally.","TWN":"我是指你的內心，我聽到你的心裡在哭。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……마음?","JPN":"……心？","ENG":"Um, mentally?","TWN":"……我的內心？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그래, 무슨 일인지 내게 털어놔 보겠니?","JPN":"ええ、何があったのか、私に話してごらんなさい。","ENG":"So, would you like someone to talk about it with?","TWN":"嗯嗯，你要跟我說說看發生什麼事嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어쩌면 내가 도울 일이 있을지도 모르지 않느냐.","JPN":"もしかしたら、私が助けてあげられるかもしれないでしょ？","ENG":"Who knows? Maybe I could be of help?","TWN":"或許我可以幫上忙。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"……그래서 혼자 거기 있었던 거예요.","JPN":"……それで、一人であそこにいたのです。","ENG":"...That’s why I was there by myself.","TWN":"……所以我才會一個人在那裡。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"으음……. 참 고약한 경우가 다 있구나.","JPN":"うーん、本当にひどい話だわ。","ENG":"Hmm... You must be going through a lot.","TWN":"嗯……聽起來確實滿慘的！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"범인이랑 얼굴이 비슷한 것 가지고 살인범으로 몰다니……. 죄다 경솔한 것들뿐이군.","JPN":"犯人と顔が似てるからって、それだけで殺人犯扱いだなんて……\\n浅はかな奴らばかりなのね。","ENG":"Calling you a murderer because you look similar to the culprit...? That’s the worst excuse I’ve ever heard.","TWN":"竟然因為長得和犯人很像，就被人當作是殺人犯……似乎太過草率！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"도와 주신 건 감사하지만……. 제가 여기 있으면 세실리아 씨까지 공범으로 몰릴지도 몰라요.","JPN":"助けてくださったことはありがたいのですが……\\n私がここにいたら、セシリアさんまで共犯扱いされるかもしれません。","ENG":"Thank you for your assistance. But if I stay here any longer, Cecilia, you might be charged as a co-conspirator.","TWN":"謝謝你的幫忙……但我怕我待在這裡，他們會把你視為是共犯。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"흐으으음……. 그야 그렇다만 여기서 영입 대상 1호를 잃어 버리면 곤란한데……. ","JPN":"うーん……それはそうだけど、ここでスカウト対象第1号を失うのは困るし……","ENG":"Hmm... True, but it’d be a waste of a perfect opportunity to recruit you...","TWN":"嗯嗯嗯……話雖如此，不過失去第一個要拉攏的對象有點可惜呢…… "},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"알파트릭스를 무너뜨릴 나의 원대한 계획이…….","JPN":"アルファトリックスを倒す、私の壮大な計画が……","ENG":"My grand plan to bring Alphatrix down...","TWN":"那我要打倒阿爾法崔克斯的偉大計劃……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"원대한 계획이요?","JPN":"壮大な計画、ですか？","ENG":"Grand plan?","TWN":"偉大計劃？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아차……. 또 속마음이 입밖으로 나와 버렸구나.","JPN":"しまった……また本音がポロっと……","ENG":"Uh-oh... Again, please excuse my monologue.","TWN":"哎呀……又不小心透露出心底話！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"후후, 어쩔 수 없지.","JPN":"ふふっ、仕方ないわね。","ENG":"Haha. Guess there’s only one thing I can do.","TWN":"呵呵，好吧！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"아버지가 늘 하던 말이 있단다. 곤경에 빠진 사람을 외면해선 안 된다고.","JPN":"父さんがいつも言っていたのよ。困っている人がいたら見て見ぬふりをしてはいけないって。","ENG":"Father taught me that I should help people in trouble.","TWN":"爸爸常跟我說，不可以對陷入困境的人視而不見。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아, 저도 그 말 들었어요!","JPN":"あ、私も同じことを言われました！","ENG":"Oh! He said that to me too!","TWN":"喔！我也有聽說那句話！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"할아버님께서 세실리아 씨에게도 같은 말을 해 주셨군요.","JPN":"お祖父様はセシリアさんにも同じ言葉をかけていたのですね。","ENG":"Grandfather must’ve said the same thing to you too, Cecilia.","TWN":"爺爺也有對你說一樣的話嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"……그럼. 재주를 가지고 있으면 남에게 베풀 줄도 알아야지.","JPN":"……もちろん。天から授かった才能は、人に施すべき。","ENG":"It’s virtuous to help out whenever you can.","TWN":"……對，有能力的人，就必須要照顧其他人。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"그러니 안심해라. 내 기꺼이 너에게 힘이 되어 주마.","JPN":"だから安心して。喜んで君の力になってあげるわ。","ENG":"So rest assured. I will aid you.","TWN":"你放心吧！我會幫你的！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 하지만 그러다간 세실리아 씨까지…….","JPN":"え？　でも、そんなことをしたらセシリアさんまで……","ENG":"Huh? But then you’ll...","TWN":"真的嗎？可是我怕連你也……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭘 새삼스럽게. 원래부터 집안에서 내쳐진 데다가 그런 선언까지 대놓고 했는데.","JPN":"なにを今更。元々実家から追放されてるし、あんな宣言までしちゃったんだから。","ENG":"Oh, come on. You know I've already been kicked out of the family and that I've declared my hatred for them.","TWN":"跟我客氣什麼！反正我本來就被趕出家門，而且還信誓旦旦地說出那些話。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"사업이란 리스크를 감수해야지. 유능한 인재에게 빚을 지워 두기 좋은 기회 아니냐.","JPN":"ビジネスをやるからにはリスクも覚悟しないと。有能な人材に貸しを作る良いチャンスだからね。","ENG":"Business is always about taking risks. Plus, it’s nice to know that you’ll owe me one someday.","TWN":"做生意本來就是有風險的，這是個投資人才的好機會！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어? 이건 무슨 소리죠?","JPN":"うん？　これは何の音でしょう。","ENG":"Huh? What was that?","TWN":"嗯？這是什麼聲音？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"크흠, 흠. 그게 사업하느라 여기저기 돈을 빌리고 다녔더니 찾아오는 것들이 많아서…….","JPN":"コホン。実はね、ビジネスのためにあちこちからお金を借りてたら、招かれざる客が増えて……","ENG":"Ahem, hmm. I borrowed some money to start my business, but they keep nagging me to pay them back...","TWN":"咳咳，因為我有到處借錢來做生意，很多人會上門討債……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"근처에 누가 얼씬거리면 알람이 울리게 해 뒀다.","JPN":"誰かが近づいたら、アラートが鳴るようにしておいたのよ。","ENG":"So I set up an alarm to ring whenever someone comes near.","TWN":"所以只要有人出現在附近，警報器就會響。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"어디 보자……. CCTV 영상을 띄우려면…….","JPN":"どれどれ……防犯カメラの映像を出すには……","ENG":"Let’s see here... If I can just get the security footage to show up...","TWN":"我來看看……打開CCTV畫面……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"어? 라파엘라 씨랑…… 이진 언니?","JPN":"あれ？　ラファエラさんと……ホノカさん？","ENG":"Huh? That’s Raphaela and... Jin?","TWN":"嗯？是拉菲樂……和李珍姐？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"큰일이에요. 감찰과 분들이 저를 잡으러 왔나 봐요.","JPN":"大変です。監察課の方が私を捕まえにきたみたいです。","ENG":"This is bad...! Investigations is here to take me away.","TWN":"不好了，監察科人應該是要來抓我的。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"뭣이?","JPN":"何ですって！","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"이, 이를 어쩐다. 여기엔 변변한 무기도 없는데.","JPN":"ど、どうしよう。ここにはろくな武器も無いのに……","ENG":"What do we do? This place doesn’t have anything that can be used as a weapon.","TWN":"這…這可怎麼辦才好？我這裡連個像樣的武器都沒有！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"다른 분들은 모두 저를 위해서 위험을 감수하셨어요.","JPN":"私のために、皆さんが体を張ってくれました。","ENG":"Everyone has risked their life for me.","TWN":"大家都因為我而身陷危險之中。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"그 분들을 위해서라도……. 저는 꼭 범인을 찾아야 해요.","JPN":"あの方たちのためにも……私は必ず犯人を見つけ出さなければなりません。","ENG":"Even if it’s only for them, I need to find the true culprit.","TWN":"我一定要揪出犯人來……才不會辜負他們的心意。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"친절을 베풀어 주는 사람에게는 꼭 보답해야 하니까요.","JPN":"親切にしてくれる方には、きちんと恩義を返すべきですから。","ENG":"I must repay those who have shown me kindness.","TWN":"我一定要報答那些對我好的人。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CECILIA_NPC_ALPHA_NULL","text":{"KOREA":"으음……. 그래도 너 혼자서 어떻게 하려고?","JPN":"うーん……でも、君ひとりでどうするつもりなの？","ENG":"Mmm... So what are you going to do about it on your own?","TWN":"嗯嗯……但你一個人打算怎麼辦？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CECILIA_NPC_ALPHA_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"괜찮아요, 세실리아 씨. 싸울 때는 혼자가 아닌 걸요.","JPN":"大丈夫ですよ、セシリアさん。戦う時はひとりではありませんから。","ENG":"It’s okay, Cecilia. I’m not alone when I fight.","TWN":"沒問題的，我在戰鬥時不是孤單一人。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"……정말 이런 곳에 계신다고요?","JPN":"……本当にこんなところにいらっしゃるんですか？","ENG":"She’s really in there?","TWN":"……小姐真的在這種地方嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L41_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"응. <color=#ffd34c>파사의 목소리</color>가 그렇게 속삭여 줬거든.","JPN":"うん。<color=#ffd34c>破邪の声</color>がそう囁いたからね。","ENG":"Yes. The <color=#ffd34c>Voice of Evil Eradication</color> told me so.","TWN":"對，<color=#ffd34c>破邪之聲</color>是這麼說的！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"파사의 목소리? 가브리엘 같은 말을 하는군요?","JPN":"破邪の声？　ガブリエルと同じことを言うのですね。","ENG":"Voice of Evil Eradication? You’re saying the same thing as Gabriel.","TWN":"破邪之聲？加布里埃爾也有說過相同的話呢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"준이랑은 달라!","JPN":"ジュンとは違うよ！","ENG":"I’m not like Jun!","TWN":"我和朱恩才不一樣！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그리고 아줌마는 증인이잖아? 감찰과도 아닌데 왜 자꾸 따라오는 거야?","JPN":"それに、おばさんは証人でしょ？　監察課でもないのになんでついてくるの？","ENG":"Also, you’re not Investigations, you’re a witness! What are you doing follow us around?","TWN":"我說大嬸你是證人吧？又不是監察科的人，幹嘛一直跟著我們？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그 상태로는 병원부터 가야 하는 거 아냐?","JPN":"その状態なら、まずは病院へ行くべきじゃない？","ENG":"Don’t you think you should visit the hospital?","TWN":"你傷得這麼重，應該先去醫院吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"부상은 괜찮습니다. 일단은 카운터이기도 하고…….","JPN":"ケガなら大丈夫です。一応カウンターですし……","ENG":"They’re minor wounds. Also, I am a Counter, so...","TWN":"我的傷沒事，我再怎麼說也是個制裁者……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아직 아가씨의 대답을 듣지 못했으니까요.","JPN":"まだお嬢様の返事も聞けていませんので。","ENG":"And I haven’t gotten an answer back from Miss Jia.","TWN":"而且我還沒聽到小姐的回答。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"흐응. 그렇단 말이지.","JPN":"ふうん、なるほどね。","ENG":"Hmm... If you say so.","TWN":"哼，原來是因為這樣。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"마음대로 해. 하지만 감찰과 일을 방해하면 내가 혼내 줄 거야.","JPN":"まあ、好きにすれば？　だけど監察課の仕事を邪魔したら、痛い目にあわせるからね？","ENG":"Do what you want. But if you interfere with our work, I will punish you myself.","TWN":"隨便你吧，不過我可是先提醒你，要是你敢妨礙監察科做事，我會生氣喔！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"꼼짝 마라, 이노베이션 대표!","JPN":"動くな、イノベーション代表！","ENG":"Freeze! CEO of Innovation!","TWN":"不許動！改革代表！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L9_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"……어? 왜 아무도 없지?","JPN":"……あれ？　なんで誰もいないの？","ENG":"Huh? Why’s no one here?","TWN":"……嗯？人呢？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"아무래도 저희가 너무 소란스럽게 온 것 같군요.","JPN":"どうやら気づかれたようですね。","ENG":"I guess we made too much noise coming in.","TWN":"看來我們打草驚蛇了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"웃……! 대표가 잔뜩 늘어났어!","JPN":"げっ……！　代表がたくさん増えた！","ENG":"Huh?! I’m seeing Jias everywhere!","TWN":"唔……！有好多代表！"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"침착하세요. 저건 아가씨의 능력입니다. 저희가 오는 줄 알고 준비해 두신 모양이에요.","JPN":"落ち着いてください。あれはお嬢様の能力です。\\n私たちが来ると知って事前に準備されたようですね。","ENG":"Calm down. This is Jia’s ability. It appears she got word of us coming.","TWN":"冷靜點，那些都是小姐的分身，應該是知道我們會來而特地準備的。"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그럼 저게 다 홀로그램이라고……? 진짜랑 똑같은데?","JPN":"じゃあ、あれは全部ホログラム……？　本物そっくりだよ？","ENG":"Then, those are all holograms...? But they look so real.","TWN":"那些全都是全息圖嗎……？長得跟本尊一模一樣欸？"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"LEEJIN_ALPHA_NULL_NULL","text":{"KOREA":"네. 다치게 할 의도는 없어 보이지만 방심하는 순간 바로 제압될 거예요.","JPN":"ええ、害を与えるつもりは無さそうですが、油断するとすぐに制圧されるでしょうね。","ENG":"Correct. They might look harmless, but they will attack if you let your guard down.","TWN":"嗯，看起來很無害的樣子，但當你卸下心房時，就會立刻被制伏。"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"흥, 상관없어. 내 추격창법은 적을 놓치지 않으니까.","JPN":"ふん、関係ないよ。私の追跡槍法は敵を逃さないから。","ENG":"Hmph! Not a problem. Because my Tracking Spearmanship never loses its target.","TWN":"哼，無所謂！我的追擊槍法是不會放過敵人的！"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEJIN_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"}}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"덤벼라! 악의 분신들!","JPN":"かかってこい！　悪の分身ども！","ENG":"Bring it! You evil clones!","TWN":"接招吧！你們這些罪犯的化身！"},"stage":{"bg":"DORMITORY_1","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};